import { buildTickReport, getStartupSession, type StartupSession, type StartupTrace } from '@/lib/startupSimData';

type ApiLoadResult = {
  endpoint?: string;
  error?: string;
  session: StartupSession;
  source: 'api' | 'local';
};

type SessionStateLike = {
  session_id?: string;
  tick?: number;
  tick_index?: number;
  world_state?: {
    mode?: string;
    cash?: number;
    cash_usd?: number;
    burn_usd_per_tick?: number;
    morale_0_100?: number;
    stage?: string;
    companies?: unknown[];
    investors?: unknown[];
    persons?: unknown[];
    employees?: unknown[];
  };
  latest_tick_report?: TickReportLike;
  tick_report?: TickReportLike;
  decision_traces?: DecisionTraceLike[];
  tool_traces?: unknown[];
};

type TickReportLike = {
  tick?: number;
  world?: {
    mode?: string;
    cash_usd?: number;
    burn_usd_per_tick?: number;
    morale_0_100?: number;
    stage?: string;
    district?: {
      companies?: number;
      investors?: number;
      employees?: number;
    };
  };
  world_state?: SessionStateLike['world_state'];
  decisions?: DecisionTraceLike[];
  decision_traces?: DecisionTraceLike[];
  tool_traces?: unknown[];
};

type DecisionTraceLike = {
  agent_id?: string;
  actor_id?: string;
  chosen?: string;
  action_chosen?: string;
  summary?: string;
  scores?: Array<{ action?: string; action_type?: string; score?: number }>;
  candidates?: Array<{ action?: string; action_type?: string; score?: number }>;
  evidence?: string[];
};

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null;
}

function toTrace(trace: DecisionTraceLike, index: number): StartupTrace {
  const scores = (trace.scores ?? trace.candidates ?? [])
    .map((item) => ({
      action: item.action ?? item.action_type ?? `candidate_${index + 1}`,
      score: item.score ?? 0,
    }))
    .slice(0, 3);

  return {
    agent: trace.agent_id ?? trace.actor_id ?? `agent_${index + 1}`,
    choice: trace.chosen ?? trace.action_chosen ?? scores[0]?.action ?? 'hold_position',
    summary: trace.summary ?? 'decision emitted by startup-sim endpoint',
    scores: scores.length > 0 ? scores : [{ action: 'hold_position', score: 0.5 }],
    evidence: trace.evidence?.length ? trace.evidence : ['api:session_state'],
  };
}

function deriveSessionFromApi(apiSessionId: string, payload: SessionStateLike | TickReportLike): StartupSession {
  const fallback = getStartupSession();
  const tickReport = 'world' in payload || 'decisions' in payload || 'decision_traces' in payload
    ? payload as TickReportLike
    : (payload as SessionStateLike).latest_tick_report ?? (payload as SessionStateLike).tick_report;
  const worldState = isRecord((payload as SessionStateLike).world_state)
    ? (payload as SessionStateLike).world_state
    : tickReport?.world_state;
  const reportWorld = tickReport?.world;

  const companiesCount = reportWorld?.district?.companies
    ?? (Array.isArray(worldState?.companies) ? worldState?.companies.length : fallback.world.companies);
  const investorsCount = reportWorld?.district?.investors
    ?? (Array.isArray(worldState?.investors) ? worldState?.investors.length : fallback.world.investors);
  const employeesCount = reportWorld?.district?.employees
    ?? (Array.isArray(worldState?.employees)
      ? worldState?.employees.length
      : Array.isArray(worldState?.persons)
        ? worldState?.persons.length
        : fallback.world.employees);

  const traces = (tickReport?.decisions ?? tickReport?.decision_traces ?? (payload as SessionStateLike).decision_traces ?? [])
    .map(toTrace)
    .slice(0, 3);

  const toolTraceCount = (tickReport?.tool_traces ?? (payload as SessionStateLike).tool_traces ?? []).length;
  const normalized = {
    ...fallback,
    id: apiSessionId,
    sessionId: (payload as SessionStateLike).session_id ?? apiSessionId,
    tick: tickReport?.tick ?? (payload as SessionStateLike).tick ?? (payload as SessionStateLike).tick_index ?? fallback.tick,
    ticksTotal: fallback.ticksTotal,
    deterministic: fallback.deterministic,
    mode: reportWorld?.mode ?? worldState?.mode ?? fallback.mode,
    world: {
      cashUsd: reportWorld?.cash_usd ?? worldState?.cash_usd ?? worldState?.cash ?? fallback.world.cashUsd,
      burnUsdPerTick: reportWorld?.burn_usd_per_tick ?? worldState?.burn_usd_per_tick ?? fallback.world.burnUsdPerTick,
      morale0100: reportWorld?.morale_0_100 ?? worldState?.morale_0_100 ?? fallback.world.morale0100,
      stage: reportWorld?.stage ?? worldState?.stage ?? fallback.world.stage,
      companies: companiesCount,
      investors: investorsCount,
      employees: employeesCount,
    },
    traces: traces.length > 0 ? traces : fallback.traces,
  };

  return {
    ...normalized,
    title: `${companiesCount} companies in motion.`,
    subtitle: `${investorsCount} investors and ${employeesCount} employees routed from startup-sim state.`,
    metrics: {
      runway: `${Math.max(1, Math.round(normalized.world.cashUsd / Math.max(normalized.world.burnUsdPerTick, 1) * 10) / 10)} mo`,
      runwayDelta: normalized.deterministic ? 'golden-seed' : 'live',
      morale: `${normalized.world.morale0100}%`,
      moraleDelta: traces.length > 0 ? `+${traces.length} traces` : 'steady',
      readiness: `${Math.min(99, 30 + companiesCount * 8)}%`,
      readinessDelta: `${toolTraceCount} tool traces`,
      headcount: `${employeesCount}`,
      headcountDelta: `${companiesCount} companies`,
    },
    timeline: traces.map((trace, index) => `Tick ${normalized.tick - index}: ${trace.agent} chose ${trace.choice}. ${trace.summary}`),
    signals: [
      { label: 'API source', value: 'Connected' },
      { label: 'Tool traces', value: `${toolTraceCount}` },
      { label: 'World stage', value: normalized.world.stage },
    ],
  };
}

export async function loadStartupSession(sessionId?: string): Promise<ApiLoadResult> {
  const fallback = getStartupSession(sessionId);
  const baseUrl = process.env.STARTUP_SIM_API_BASE_URL;

  if (!baseUrl) {
    return { session: fallback, source: 'local' };
  }

  const normalizedBase = baseUrl.replace(/\/$/, '');
  const resolvedSessionId = sessionId ?? fallback.id;
  const endpoint = `${normalizedBase}/session/${resolvedSessionId}/state`;

  try {
    const response = await fetch(endpoint, {
      headers: { Accept: 'application/json' },
      next: { revalidate: 0 },
    });

    if (!response.ok) {
      return {
        endpoint,
        error: `HTTP ${response.status}`,
        session: fallback,
        source: 'local',
      };
    }

    const payload = await response.json();
    if (!isRecord(payload)) {
      return {
        endpoint,
        error: 'Invalid JSON payload',
        session: fallback,
        source: 'local',
      };
    }

    return {
      endpoint,
      session: deriveSessionFromApi(resolvedSessionId, payload as SessionStateLike),
      source: 'api',
    };
  } catch (error) {
    return {
      endpoint,
      error: error instanceof Error ? error.message : 'Unknown error',
      session: fallback,
      source: 'local',
    };
  }
}

export function serializeTickReport(session: StartupSession) {
  return JSON.stringify(buildTickReport(session), null, 2);
}
